namespace ResearchAgent;

public sealed class NoteStore
{
    private readonly List<Note> _notes = [];

    public void Add(string title, string content) =>
        _notes.Add(new Note(title, content, DateTime.UtcNow));

    public IReadOnlyList<Note> GetAll() => _notes.AsReadOnly();

    public void Clear() => _notes.Clear();
}

public sealed record Note(string Title, string Content, DateTime SavedAt);

using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;
using System.Web;

namespace ResearchAgent;

public static class WebSearcher
{
    /// <summary>
    /// Searches the web using the DuckDuckGo Instant Answer API (no API key required).
    /// Falls back to returning the query URL if the API returns no results.
    /// </summary>
    public static async Task<string> SearchAsync(HttpClient httpClient, string query)
    {
        try
        {
            var encoded = HttpUtility.UrlEncode(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            httpClient.DefaultRequestHeaders.UserAgent.TryParseAdd("ResearchAgent/1.0");

            var response = await httpClient.GetFromJsonAsync<DdgResponse>(url);

            var results = new List<string>();

            if (!string.IsNullOrWhiteSpace(response?.Abstract))
            {
                results.Add($"**{response.Heading}**\n{response.Abstract}\nSource: {response.AbstractURL}");
            }

            if (response?.RelatedTopics is { Count: > 0 })
            {
                foreach (var topic in response.RelatedTopics.Take(5))
                {
