using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Configuration;
using Microsoft.Agents.AI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddHttpClient();

builder.Services.AddChatClient(chatClientBuilder => chatClientBuilder
    .UseOpenAIChatClient(
        builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18",
        builder.Configuration["AI:ApiKey"]
            ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
            ?? throw new InvalidOperationException(
                "Set AI:ApiKey in config or OPENAI_API_KEY environment variable.")));

builder.Services.AddSingleton<NoteStore>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteStore = host.Services.GetRequiredService<NoteStore>();
var httpClientFactory = host.Services.GetRequiredService<IHttpClientFactory>();

var tools = new[]
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
        {
            return WebSearcher.SearchAsync(httpClientFactory.CreateClient(), query);
        },
        name: "web_search",
        description: "Search the web for information on a topic. Returns a list of result titles, URLs, and snippets."),

    AIFunctionFactory.Create(
        ([Description("Title or label for the note")] string title,
         [Description("Content of the note")] string content) =>
        {
            noteStore.Add(title, content);
            return $"Note saved: \"{title}\"";
        },
        name: "save_note",
        description: "Save a research note with a title and content for later use in the summary."),

    AIFunctionFactory.Create(
        () =>
        {
            var notes = noteStore.GetAll();
            return notes.Count == 0
                ? "No notes saved yet."
                : string.Join("\n\n", notes.Select(n => $"## {n.Title}\n{n.Content}"));
        },
        name: "get_notes",
        description: "Retrieve all saved research notes."),
};

var agent = new ChatClientAgent(chatClient,
    """
    You are a research agent. When given a topic:
    1. Use web_search to find relevant information (perform 2-3 searches with different queries).
    2. Use save_note to record key findings from each search.
    3. Use get_notes to review all collected notes.
    4. Produce a well-structured summary with sections, key points, and source URLs.
    Be thorough but concise. Always cite your sources.
    """,
    tools);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    noteStore.Clear();
    Console.WriteLine($"\nResearching: {topic}\n");

    var messages = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
    };

    var options = new AgentInvokeOptions { MaximumIterations = 10 };

    try
    {
        await foreach (var response in agent.InvokeStreamingAsync(messages, options))
        {
            if (!string.IsNullOrEmpty(response.Text))
                Console.Write(response.Text);
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}");
    }

    Console.WriteLine("\n");
}

