 using System.ComponentModel;
 using Microsoft.Extensions.AI;
 using Microsoft.Agents.AI;
 using OpenAI;
 using ResearchAgent;

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 // Create IChatClient from OpenAI SDK via MEAI extension
 var openAIClient = new OpenAIClient(apiKey);
 IChatClient chatClient = openAIClient.GetChatClient(modelId).AsIChatClient();

 var httpClient = new HttpClient();
 var noteStore = new NoteStore();

 // Define tools the agent can use
 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(
         ([Description("The search query")] string query) =>
             WebSearcher.SearchAsync(httpClient, query),
         name: "web_search",
         description: "Search the web for information on a topic. Returns a list of result titles, URLs, and snippets."),

     AIFunctionFactory.Create(
         ([Description("Title or label for the note")] string title,
          [Description("Content of the note")] string content) =>
         {
             noteStore.Add(title, content);
             return $"Note saved: \"{title}\"";
         },
         name: "save_note",
         description: "Save a research note with a title and content for later use in the summary."),

     AIFunctionFactory.Create(
         () =>
         {
             var notes = noteStore.GetAll();
             return notes.Count == 0
                 ? "No notes saved yet."
                 : string.Join("\n\n", notes.Select(n => $"## {n.Title}\n{n.Content}"));
         },
         name: "get_notes",
         description: "Retrieve all saved research notes."),
 };

 // Build the agent with tools and instructions
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. When given a topic:
         1. Use web_search to find relevant information (perform 2-3 searches with varied queries).
         2. Use save_note to record key findings from each search.
         3. Use get_notes to review all collected notes.
         4. Produce a well-structured summary with sections, key points, and source URLs.
         Be thorough but concise. Always cite your sources.
         """,
     name: "ResearchAgent",
     tools: tools);

 var runOptions = new ChatClientAgentRunOptions(
     new ChatOptions
     {
         ModelId = modelId,
         Temperature = 0f,
         MaxOutputTokens = 2048,
     });

 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       🔍 Research Agent              ║");
 Console.WriteLine("╠══════════════════════════════════════╣");
 Console.WriteLine("║  Enter a topic to research.          ║");
 Console.WriteLine("║  Type 'quit' to exit.                ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine();

 while (true)
 {
     Console.Write("Research topic> ");
     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     noteStore.Clear();
     Console.WriteLine($"\nResearching: {topic}\n");

     try
     {
         await foreach (var update in agent.RunStreamingAsync(
             $"Research the following topic and provide a comprehensive summary: {topic}",
             session: null,
             options: runOptions))
         {
             if (!string.IsNullOrEmpty(update.Text))
                 Console.Write(update.Text);
         }
     }
     catch (Exception ex)
     {
         Console.WriteLine($"\nError: {ex.Message}");
     }

     Console.WriteLine("\n");
 }
